import{_ as a,o as d,c as e,ag as s}from"./chunks/framework.DEs8X8sU.js";const u=JSON.parse('{"title":"メニュー管理","description":"","frontmatter":{"feature_id":"MENU","title":"メニュー管理","chapter":4,"plan":["all"],"role":["owner","manager"],"audience":"店長以上","keywords":["メニュー","カテゴリ","価格","本部マスタ","店舗オーバーライド","品切れ","オプション","多言語翻訳","CSV"],"related":["03-dashboard","11-inventory","15-owner","22-smaregi-full"],"last_updated":"2026-04-19T00:00:00.000Z","maintainer":"POSLA運営"},"headers":[],"relativePath":"tenant/04-menu.md","filePath":"tenant/04-menu.md"}'),o={name:"tenant/04-menu.md"};function l(n,t,i,r,c,p){return d(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="_4-メニュー管理" tabindex="-1">4. メニュー管理 <a class="header-anchor" href="#_4-メニュー管理" aria-label="Permalink to &quot;4. メニュー管理&quot;">​</a></h1><p>メニュー管理では、お客さんに表示するメニューの作成・編集・品切れ管理を行います。POSLAのメニューは<strong>3層構造</strong> (本部マスタ → 店舗オーバーライド → 店舗限定品) になっており、本部で統一メニューを管理しつつ、店舗ごとに価格や表示をカスタマイズできます。</p><hr><h2 id="_4-0-はじめにお読みください" tabindex="-1">4.0 はじめにお読みください <a class="header-anchor" href="#_4-0-はじめにお読みください" aria-label="Permalink to &quot;4.0 はじめにお読みください&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">章の読み方ガイド</p><ul><li><strong>単店舗</strong>: 4.1 カテゴリ + 4.2 メニューテンプレート + 4.4 限定メニュー が中心</li><li><strong>多店舗 / チェーン</strong>: 4.2 本部マスタ + 4.3 店舗オーバーライド の両軸を使う</li><li><strong>一括入力</strong>: 4.10 CSV インポート / 4.11 スマレジ連携</li><li><strong>多言語対応</strong>: 4.9 AI 翻訳機能（Gemini）</li><li><strong>困ったとき</strong>: 4.Y トラブルシューティング → 4.X FAQ</li></ul></div><h3 id="_4-0-1-操作前のチェックリスト" tabindex="-1">4.0.1 操作前のチェックリスト <a class="header-anchor" href="#_4-0-1-操作前のチェックリスト" aria-label="Permalink to &quot;4.0.1 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>チェック項目</th><th>確認方法</th></tr></thead><tbody><tr><td>ログインしているロールが <code>owner</code> または <code>manager</code> であること</td><td>画面右上のユーザーバッジに <code>owner</code> / <code>manager</code> 表示があるか</td></tr><tr><td>操作対象店舗を正しく選択していること（店舗単位の画面のみ）</td><td>ヘッダーの店舗セレクターで対象店舗を選択</td></tr><tr><td>本部一括配信アドオンの契約有無</td><td>owner-dashboard に「本部メニュー」タブが出るか</td></tr><tr><td>編集対象が本部マスタか店舗かを区別していること</td><td>本章 4.0.2 の表で確認</td></tr><tr><td>カテゴリが先に作成済みであること</td><td>カテゴリ未作成だとメニュー追加時にカテゴリ選択ができない</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">権限について</p><ul><li><code>staff</code> ロールはメニュー編集ができません（読取は可能）。意図的な制約です（誤操作・退職スタッフによる価格改竄を防ぐため）</li><li><code>device</code> ロール（KDS / レジ端末）はメニュー編集 UI に到達できません</li><li>本部マスタ（<code>menu_templates</code>）の編集は <code>owner</code> 専用（hq_menu_broadcast=1 のテナント）</li></ul></div><h3 id="_4-0-2-posla-メニュー-3-層構造" tabindex="-1">4.0.2 POSLA メニュー 3 層構造 <a class="header-anchor" href="#_4-0-2-posla-メニュー-3-層構造" aria-label="Permalink to &quot;4.0.2 POSLA メニュー 3 層構造&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ menu_templates        (本部マスタ)                           │</span></span>
<span class="line"><span>│   tenant 単位、全店共通                                      │</span></span>
<span class="line"><span>│   name / name_en / category / base_price / image_url         │</span></span>
<span class="line"><span>│   description / calories / allergens                         │</span></span>
<span class="line"><span>└──────────┬──────────────────────────────────────────────────┘</span></span>
<span class="line"><span>           │ 店舗ごとに上書き / 非表示 / 品切れ</span></span>
<span class="line"><span>           ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ store_menu_overrides  (店舗オーバーライド)                   │</span></span>
<span class="line"><span>│   store 単位                                                 │</span></span>
<span class="line"><span>│   price=NULL → 本部 base_price 継承                          │</span></span>
<span class="line"><span>│   is_hidden=1 → この店舗で非表示                             │</span></span>
<span class="line"><span>│   is_sold_out=1 → この店舗で品切れ                           │</span></span>
<span class="line"><span>│   override_image_url → 店舗固有画像                          │</span></span>
<span class="line"><span>└──────────┬──────────────────────────────────────────────────┘</span></span>
<span class="line"><span>           │ お客さん画面では統合表示</span></span>
<span class="line"><span>           ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ store_local_items     (店舗限定品)                           │</span></span>
<span class="line"><span>│   store 単位、本部マスタに紐づかない独自メニュー             │</span></span>
<span class="line"><span>│   その店舗でしか出ない                                       │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                          ↓</span></span>
<span class="line"><span>            api/lib/menu-resolver.php の resolve_store_menu()</span></span>
<span class="line"><span>            が 3 層を統合してセルフオーダー / KDS に返す</span></span></code></pre></div><h3 id="_4-0-3-本部一括配信アドオン" tabindex="-1">4.0.3 本部一括配信アドオン <a class="header-anchor" href="#_4-0-3-本部一括配信アドオン" aria-label="Permalink to &quot;4.0.3 本部一括配信アドオン&quot;">​</a></h3><p><code>tenants.hq_menu_broadcast = 1</code>（基本料金 + アドオン ¥3,000/店舗 契約）の tenant では、編集権限が階層化されます。</p><table tabindex="0"><thead><tr><th>編集対象</th><th>アドオン契約あり</th><th>アドオン契約なし</th></tr></thead><tbody><tr><td>本部マスタ（<code>menu_templates</code>）</td><td><strong>owner-dashboard</strong> からのみ（owner 専用）</td><td>dashboard「店舗メニュー」から事実上編集可</td></tr><tr><td>店舗オーバーライド（価格・非表示・品切れ）</td><td>店舗 dashboard から（manager 以上）</td><td>同左</td></tr><tr><td>店舗限定品（<code>store_local_items</code>）</td><td>店舗 dashboard「限定メニュー」から</td><td>同左</td></tr><tr><td>本部マスタの readonly フィールド（店舗側）</td><td>name / name_en / category_id / calories / allergens / base_price / image_url が<strong>ロック</strong></td><td>ロックなし</td></tr></tbody></table><p>実装フラグ: <code>MenuOverrideEditor.init(container, features)</code> の <code>features.hq_menu_broadcast</code> で <code>_isHqLocked</code> が決まります（P1-29）。</p><p>管理ダッシュボードの**「メニュー管理」タブ**をクリックし、以下のサブタブを切り替えて操作します：</p><ul><li><strong>カテゴリ管理</strong>（カテゴリ + テンプレートメニュー一覧）</li><li><strong>店舗メニュー</strong>（店舗オーバーライド + おすすめ）</li><li><strong>限定メニュー</strong>（店舗独自品）</li><li><strong>オプション管理</strong>（オプショングループ + 選択肢）</li></ul><hr><h2 id="_4-1-カテゴリ管理" tabindex="-1">4.1 カテゴリ管理 <a class="header-anchor" href="#_4-1-カテゴリ管理" aria-label="Permalink to &quot;4.1 カテゴリ管理&quot;">​</a></h2><p>カテゴリは、メニューをグループ分けする単位です。セルフオーダー画面やハンディPOS画面でカテゴリごとにメニューが表示されます。</p><p><strong>サブタブ：「カテゴリ管理」</strong></p><h3 id="_4-1-1-画面の見方" tabindex="-1">4.1.1 画面の見方 <a class="header-anchor" href="#_4-1-1-画面の見方" aria-label="Permalink to &quot;4.1.1 画面の見方&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[カテゴリ管理] サブタブ</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  カテゴリ (3)                       [+ カテゴリ追加] │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  1  前菜          (Appetizers)         [編集] [削除] │</span></span>
<span class="line"><span>│  2  メイン        (Main)               [編集] [削除] │</span></span>
<span class="line"><span>│  3  デザート      (Dessert)            [編集] [削除] │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><p>カテゴリは表示順に並び、横に通し番号が表示されます。</p><h3 id="_4-1-2-カテゴリの作成" tabindex="-1">4.1.2 カテゴリの作成 <a class="header-anchor" href="#_4-1-2-カテゴリの作成" aria-label="Permalink to &quot;4.1.2 カテゴリの作成&quot;">​</a></h3><ol><li>「カテゴリ管理」サブタブを開く</li><li><strong>「カテゴリ追加」ボタン</strong>を押す</li><li>モーダルが開く（タイトル：「カテゴリを追加」）</li><li>以下を入力する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th><th>入力例</th></tr></thead><tbody><tr><td>カテゴリ名</td><td>✓</td><td>日本語の表示名</td><td>前菜</td></tr><tr><td>カテゴリ名（英語）</td><td>—</td><td>英語の表示名。多言語対応時に使用</td><td>Appetizers</td></tr></tbody></table><ol start="5"><li><strong>保存</strong>ボタンを押す</li><li>「カテゴリを追加しました」トーストが表示され、一覧に追加される</li></ol><h3 id="_4-1-3-カテゴリの編集" tabindex="-1">4.1.3 カテゴリの編集 <a class="header-anchor" href="#_4-1-3-カテゴリの編集" aria-label="Permalink to &quot;4.1.3 カテゴリの編集&quot;">​</a></h3><ol><li>カテゴリ一覧で、編集したいカテゴリの<strong>編集ボタン</strong>を押す</li><li>モーダルが開き、現在の値が表示される</li><li>以下を変更できる：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>カテゴリ名</td><td>日本語名</td></tr><tr><td>カテゴリ名（英語）</td><td>英語名</td></tr><tr><td>表示順</td><td>数値。小さいほど上に表示</td></tr></tbody></table><ol start="4"><li><strong>保存</strong>ボタンを押す</li></ol><h3 id="_4-1-4-カテゴリの削除" tabindex="-1">4.1.4 カテゴリの削除 <a class="header-anchor" href="#_4-1-4-カテゴリの削除" aria-label="Permalink to &quot;4.1.4 カテゴリの削除&quot;">​</a></h3><ol><li>削除したいカテゴリの<strong>削除ボタン</strong>を押す</li><li>確認ダイアログが表示される</li><li><strong>OK</strong>を押すと削除される</li></ol><div class="warning custom-block"><p class="custom-block-title">注意</p><p>カテゴリを削除すると、そのカテゴリに属するメニューは「カテゴリなし」の状態になります。削除前に、メニューを別のカテゴリに移動させることを推奨します。</p></div><h3 id="_4-1-5-並び順のルール" tabindex="-1">4.1.5 並び順のルール <a class="header-anchor" href="#_4-1-5-並び順のルール" aria-label="Permalink to &quot;4.1.5 並び順のルール&quot;">​</a></h3><ul><li>カテゴリの表示順序は「表示順」の数値（<code>sort_order</code>）で決まります</li><li>数値が小さいカテゴリが上（左）に表示されます</li><li>セルフオーダー画面・ハンディPOS画面でも同じ順序で表示されます</li><li><strong>実例（matsunoya）</strong>: 1=朝定食、2=昼定食、3=夜定食、10=サイドメニュー、99=その他、のように 10 飛ばし運用にすると、後から間に追加しやすい</li></ul><hr><h2 id="_4-2-メニューテンプレート-本部マスタ" tabindex="-1">4.2 メニューテンプレート（本部マスタ） <a class="header-anchor" href="#_4-2-メニューテンプレート-本部マスタ" aria-label="Permalink to &quot;4.2 メニューテンプレート（本部マスタ）&quot;">​</a></h2><p>メニューテンプレートは、全店舗で共通のマスターメニューです。ここで作成したメニューが全店舗の基本メニューになります。店舗ごとの価格変更や非表示設定は「店舗メニューオーバーライド」で行います。</p><p><strong>サブタブ：「カテゴリ管理」</strong>（カテゴリ一覧の下にメニュー一覧が並ぶ）</p><div class="tip custom-block"><p class="custom-block-title">アドオン契約時の制約</p><ul><li>アドオン契約 = <code>hq_menu_broadcast=1</code> の tenant では、このタブからのテンプレート追加・編集は <strong>owner-dashboard</strong> に集約されます（P1-28）</li><li>店舗 dashboard 側はマスタ項目が readonly（P1-29）。店舗側で本部マスタを編集する必要があるなら、owner にエスカレーションしてください</li></ul></div><h3 id="_4-2-1-メニューの作成" tabindex="-1">4.2.1 メニューの作成 <a class="header-anchor" href="#_4-2-1-メニューの作成" aria-label="Permalink to &quot;4.2.1 メニューの作成&quot;">​</a></h3><ol><li><strong>「メニュー追加」ボタン</strong>を押す</li><li>モーダルが開く</li><li>以下を入力する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th><th>入力例</th></tr></thead><tbody><tr><td>メニュー名</td><td>✓</td><td>日本語の表示名</td><td>特製唐揚げ</td></tr><tr><td>メニュー名（英語）</td><td>—</td><td>英語の表示名</td><td>Special Karaage</td></tr><tr><td>カテゴリ</td><td>✓</td><td>ドロップダウンからカテゴリを選択</td><td>メイン料理</td></tr><tr><td>価格（税込）</td><td>✓</td><td>税込価格（円）。0円も可（後述）</td><td>880</td></tr><tr><td>説明文</td><td>—</td><td>メニューの詳細説明</td><td>自家製タレで味付けした鶏もも肉...</td></tr><tr><td>説明文（英語）</td><td>—</td><td>英語の説明文</td><td>Chicken thigh marinated in...</td></tr><tr><td>カロリー</td><td>—</td><td>kcal 単位の数値</td><td>450</td></tr><tr><td>アレルゲン</td><td>—</td><td>25 項目のチェックボックスから選択</td><td>卵 / 小麦 / 大豆</td></tr><tr><td>画像</td><td>—</td><td>メニュー写真。ドラッグ＆ドロップまたはクリックでアップロード</td><td>—</td></tr></tbody></table><ol start="4"><li><strong>保存</strong>ボタンを押す</li><li>メニュー一覧に追加される</li></ol><div class="tip custom-block"><p class="custom-block-title">0円メニューの使い所</p><p>コース料理のフェーズ内料理（前菜→メイン→デザート）はコース定義側で価格を持つため、テンプレート側は 0 円で作成して「コース専用」として運用することがあります。</p></div><div class="tip custom-block"><p class="custom-block-title">画像について</p><ul><li>対応形式：JPEG、PNG、WebP、GIF</li><li>最大ファイルサイズ：5MB</li><li>アップロード時に自動的に 800×800 ピクセル以下にリサイズされます（品質 0.8 の JPEG）</li><li>画像なしでも作成できます。画像なしの場合は🍽️アイコンが表示されます</li><li>画像 URL は HTTPS で配信される必要があります。HTTP は混在コンテンツとしてブラウザにブロックされます</li></ul></div><h3 id="_4-2-2-アレルゲン-25-項目-実装一覧" tabindex="-1">4.2.2 アレルゲン 25 項目（実装一覧） <a class="header-anchor" href="#_4-2-2-アレルゲン-25-項目-実装一覧" aria-label="Permalink to &quot;4.2.2 アレルゲン 25 項目（実装一覧）&quot;">​</a></h3><p><code>MenuOverrideEditor._allergenList</code> / <code>LocalItemEditor._allergenList</code> に定義されている公式 25 項目：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>卵, 乳, 小麦, えび, かに, そば, 落花生, アーモンド, カシューナッツ,</span></span>
<span class="line"><span>くるみ, ごま, さけ, さば, いか, あわび, いくら, 大豆, まつたけ,</span></span>
<span class="line"><span>もも, りんご, キウイ, バナナ, オレンジ, ゼラチン,</span></span>
<span class="line"><span>鶏肉, 牛肉, 豚肉</span></span></code></pre></div><p>うち、消費者庁「特定原材料 8 品目」（卵 / 乳 / 小麦 / えび / かに / そば / 落花生 / くるみ）は法律上の表示義務があります。残りは「特定原材料に準ずる 20 品目」相当 + POSLA 独自追加（鶏肉・牛肉・豚肉）。</p><h3 id="_4-2-3-メニューの編集" tabindex="-1">4.2.3 メニューの編集 <a class="header-anchor" href="#_4-2-3-メニューの編集" aria-label="Permalink to &quot;4.2.3 メニューの編集&quot;">​</a></h3><ol><li>メニュー一覧で、編集したいメニューの<strong>編集ボタン</strong>を押す</li><li>モーダルが開き、現在の値が表示される</li><li>各項目を変更する</li><li><strong>品切れ</strong>チェックボックス：チェックを入れると<strong>全店舗で</strong>品切れ表示になります（店舗側で解除不可）</li><li><strong>保存</strong>ボタンを押す</li></ol><h3 id="_4-2-4-メニューの削除" tabindex="-1">4.2.4 メニューの削除 <a class="header-anchor" href="#_4-2-4-メニューの削除" aria-label="Permalink to &quot;4.2.4 メニューの削除&quot;">​</a></h3><ol><li>削除したいメニューの<strong>削除ボタン</strong>を押す</li><li>確認ダイアログが表示される：「このメニューを削除すると、全店舗のオーバーライド設定も削除されます」</li><li><strong>OK</strong>を押すと削除される</li></ol><div class="danger custom-block"><p class="custom-block-title">カスケード削除に注意</p><p>メニューテンプレートを削除すると、そのメニューに対する全店舗のオーバーライド設定（価格変更、品切れ状態等）も一緒に削除されます。元に戻せません。</p><p>過去注文（<code>orders.items</code> JSON カラム）は名称・価格スナップショットを保持しているため、過去レポートには影響しません。</p></div><h3 id="_4-2-5-品切れのトグル" tabindex="-1">4.2.5 品切れのトグル <a class="header-anchor" href="#_4-2-5-品切れのトグル" aria-label="Permalink to &quot;4.2.5 品切れのトグル&quot;">​</a></h3><p>メニュー一覧の各メニューに<strong>品切れボタン</strong>があります。</p><ul><li><strong>グレー</strong>（通常）→ クリックすると<strong>赤</strong>（品切れ）に変わる</li><li><strong>赤</strong>（品切れ）→ クリックすると<strong>グレー</strong>（通常）に戻る</li><li>品切れにすると、セルフオーダー画面・ハンディPOS画面で即座に「品切れ」表示になり、お客さんは注文できなくなります</li><li>メニューバージョンが自動更新され、お客さんの画面は 2 秒以内に品切れ状態が反映されます</li></ul><h3 id="_4-2-6-カテゴリでフィルター" tabindex="-1">4.2.6 カテゴリでフィルター <a class="header-anchor" href="#_4-2-6-カテゴリでフィルター" aria-label="Permalink to &quot;4.2.6 カテゴリでフィルター&quot;">​</a></h3><p>メニュー一覧の上部にカテゴリフィルターのドロップダウンがあります。カテゴリを選択すると、そのカテゴリのメニューだけが表示されます。「全て」を選択すると全メニューが表示されます。</p><hr><h2 id="_4-3-店舗メニューオーバーライド" tabindex="-1">4.3 店舗メニューオーバーライド <a class="header-anchor" href="#_4-3-店舗メニューオーバーライド" aria-label="Permalink to &quot;4.3 店舗メニューオーバーライド&quot;">​</a></h2><p>店舗メニューオーバーライドでは、本部テンプレートのメニューを店舗ごとにカスタマイズします。価格の変更、メニューの非表示、店舗固有の画像設定が可能です。</p><p><strong>サブタブ：「店舗メニュー」</strong></p><div class="warning custom-block"><p class="custom-block-title">店舗を選択してください</p><p>この画面は店舗単位で操作します。ヘッダーの店舗セレクターで、操作したい店舗を選択してから開いてください。未選択時は「店舗を選択してください」と表示されます。</p></div><h3 id="_4-3-1-画面の見方-テーブル形式" tabindex="-1">4.3.1 画面の見方（テーブル形式） <a class="header-anchor" href="#_4-3-1-画面の見方-テーブル形式" aria-label="Permalink to &quot;4.3.1 画面の見方（テーブル形式）&quot;">​</a></h3><p>テーブル形式で一覧表示されます。各行に以下の情報があります：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────┬─────────────────┬───────┬──────┬──────┬──────┬────┐</span></span>
<span class="line"><span>│ 画像 │ メニュー名      │カテゴリ│ 価格 │非表示│品切れ│操作│</span></span>
<span class="line"><span>├──────┼─────────────────┼───────┼──────┼──────┼──────┼────┤</span></span>
<span class="line"><span>│ 📷  │ 特製唐揚げ      │ メイン │¥880  │ —   │ —   │編集│</span></span>
<span class="line"><span>│ 📷  │ ステーキ重 [非表示]│ メイン │¥1480 │ ✓  │ —   │編集│</span></span>
<span class="line"><span>│ 📷  │ 季節のサラダ    │ 前菜   │¥620  │ —   │[品切]│編集│</span></span>
<span class="line"><span>└──────┴─────────────────┴───────┴──────┴──────┴──────┴────┘</span></span></code></pre></div><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>画像</td><td>店舗固有の画像（<code>override_image_url</code>）。設定がなければ本部テンプレートの画像（<code>image_url</code>）</td></tr><tr><td>メニュー名</td><td>名前（日本語/英語）</td></tr><tr><td>カテゴリ</td><td>所属カテゴリ名</td></tr><tr><td>価格</td><td>店舗価格（上書きされている場合はその価格、なければ本部価格）</td></tr><tr><td>非表示</td><td>この店舗でメニューを非表示にするかどうか。非表示の行は半透明（opacity:0.5）で表示</td></tr><tr><td>品切れ</td><td>この店舗での品切れ状態</td></tr><tr><td>操作</td><td>編集・削除ボタン</td></tr></tbody></table><p>「<strong>本部品切れ</strong>」バッジが表示されている場合、本部テンプレート側で品切れに設定されているため、店舗側で解除できません（4.2.5 でテンプレ側を解除する必要があります）。</p><h3 id="_4-3-2-メニューの価格を変更する" tabindex="-1">4.3.2 メニューの価格を変更する <a class="header-anchor" href="#_4-3-2-メニューの価格を変更する" aria-label="Permalink to &quot;4.3.2 メニューの価格を変更する&quot;">​</a></h3><ol><li>変更したいメニューの<strong>編集ボタン</strong>を押す</li><li>モーダルが開く</li><li><strong>価格</strong>欄に新しい価格を入力する（<strong>空欄にすると本部価格に戻ります</strong> = <code>price=NULL</code>）</li><li><strong>保存</strong>ボタンを押す</li></ol><div class="tip custom-block"><p class="custom-block-title">実例: matsunoya / torimaru</p><ul><li>matsunoya 渋谷店：本部 base_price ¥880 → 渋谷店 ¥980（家賃調整）</li><li>matsunoya 横浜店：本部 base_price ¥880 → 価格上書きなし（本部価格を継承）</li><li>torimaru：本部マスタを直接編集（hq_menu_broadcast=0 のため）</li></ul></div><h3 id="_4-3-3-メニューを非表示にする" tabindex="-1">4.3.3 メニューを非表示にする <a class="header-anchor" href="#_4-3-3-メニューを非表示にする" aria-label="Permalink to &quot;4.3.3 メニューを非表示にする&quot;">​</a></h3><p>この店舗では提供しないメニューを非表示にできます（例：ランチ専門店は夜定食を非表示）。</p><ol><li>メニュー一覧で、非表示にしたいメニューの<strong>非表示トグル</strong>を押す</li><li>メニューが半透明表示になり、セルフオーダー画面に表示されなくなります</li><li>もう一度押すと表示に戻ります</li></ol><h3 id="_4-3-4-品切れにする" tabindex="-1">4.3.4 品切れにする <a class="header-anchor" href="#_4-3-4-品切れにする" aria-label="Permalink to &quot;4.3.4 品切れにする&quot;">​</a></h3><ol><li>メニュー一覧で、品切れにしたいメニューの<strong>品切れトグル</strong>を押す</li><li>赤いバッジが表示され、セルフオーダー画面で品切れ表示になります</li><li>もう一度押すと品切れを解除できます</li></ol><h3 id="_4-3-5-カロリー・アレルゲン情報を設定する" tabindex="-1">4.3.5 カロリー・アレルゲン情報を設定する <a class="header-anchor" href="#_4-3-5-カロリー・アレルゲン情報を設定する" aria-label="Permalink to &quot;4.3.5 カロリー・アレルゲン情報を設定する&quot;">​</a></h3><p>メニューの編集モーダルで、以下を設定できます：</p><table tabindex="0"><thead><tr><th>項目</th><th>説明</th><th>入力方法</th></tr></thead><tbody><tr><td>カロリー</td><td>kcal 単位の数値</td><td>数値入力（例：450）</td></tr><tr><td>アレルゲン</td><td>含まれるアレルゲン</td><td>チェックボックスから選択（25 項目から複数選択可）</td></tr></tbody></table><p>設定したカロリーとアレルゲンはセルフオーダー画面のメニュー詳細に表示されます。</p><div class="tip custom-block"><p class="custom-block-title">アレルゲン情報の運用</p><ul><li>法律上の表示義務（特定原材料 8 品目）は調理工程で混入する可能性も含めて表示する必要があります</li><li>「コンタミ」（製造ライン共通による微量混入）が想定される場合は、説明文に「※製造工程上、卵を含む製品と共通の設備で製造しています」のように記載</li><li>アレルゲン情報を更新したら必ず<strong>多言語翻訳の再実行</strong>を推奨（4.9 参照）</li></ul></div><h3 id="_4-3-6-オプショングループを紐付ける" tabindex="-1">4.3.6 オプショングループを紐付ける <a class="header-anchor" href="#_4-3-6-オプショングループを紐付ける" aria-label="Permalink to &quot;4.3.6 オプショングループを紐付ける&quot;">​</a></h3><p>メニューの編集モーダルの下部に、オプショングループの紐付け設定があります。</p><ol><li>編集モーダルを開く</li><li>下部の「オプション」セクションを確認する</li><li>紐付けたいオプショングループに<strong>チェック</strong>を入れる</li><li>「必須」チェックボックス：チェックを入れると、お客さんは注文時にこのオプションを必ず選択する必要があります</li><li><strong>保存</strong>を押す</li></ol><h3 id="_4-3-7-店舗固有の画像を設定する" tabindex="-1">4.3.7 店舗固有の画像を設定する <a class="header-anchor" href="#_4-3-7-店舗固有の画像を設定する" aria-label="Permalink to &quot;4.3.7 店舗固有の画像を設定する&quot;">​</a></h3><ol><li>編集モーダルを開く</li><li><strong>画像アップロード</strong>エリアに画像をドラッグ＆ドロップ、またはクリックして選択</li><li>プレビューが表示される</li><li><strong>保存</strong>を押す</li><li>この店舗では、本部テンプレートの画像の代わりにこの画像が表示されます</li></ol><h3 id="_4-3-8-アドオン契約時の-readonly-挙動" tabindex="-1">4.3.8 アドオン契約時の readonly 挙動 <a class="header-anchor" href="#_4-3-8-アドオン契約時の-readonly-挙動" aria-label="Permalink to &quot;4.3.8 アドオン契約時の readonly 挙動&quot;">​</a></h3><p><code>hq_menu_broadcast=1</code> の tenant では、店舗 dashboard 「店舗メニュー」タブから編集モーダルを開いても以下の項目はグレーアウトされて編集できません（P1-29）：</p><ul><li>メニュー名（日本語 / 英語）</li><li>カテゴリ</li><li>カロリー</li><li>アレルゲン</li><li>本部マスタ価格（base_price）</li><li>本部マスタ画像（image_url）</li></ul><p>編集できるのは：</p><ul><li>店舗価格（<code>price</code>、空欄で本部継承）</li><li>店舗画像（<code>override_image_url</code>）</li><li>非表示フラグ（<code>is_hidden</code>）</li><li>品切れフラグ（<code>is_sold_out</code>）</li><li>紐付けオプショングループ + 必須フラグ</li></ul><p>これらマスタ項目を変更したい場合は owner-dashboard「本部メニュー」タブから操作してください。</p><hr><h2 id="_4-4-店舗限定メニュー" tabindex="-1">4.4 店舗限定メニュー <a class="header-anchor" href="#_4-4-店舗限定メニュー" aria-label="Permalink to &quot;4.4 店舗限定メニュー&quot;">​</a></h2><p>店舗限定メニューは、特定の店舗でのみ提供するオリジナルメニューです。本部テンプレートには存在しない、その店舗だけのメニューを作成できます。</p><p><strong>サブタブ：「限定メニュー」</strong></p><div class="warning custom-block"><p class="custom-block-title">「限定メニュー」と「店舗メニュー」の違い</p><ul><li>「店舗メニュー」 = 本部マスタ + 店舗オーバーライドの統合表示（既存品の調整）</li><li>「限定メニュー」 = その店舗だけの独自品（新規追加）</li></ul><p>新規メニューを「店舗メニュー」タブから追加すると本部マスタに入ってしまいます（アドオン未契約時）。<strong>店舗独自品は必ず「限定メニュー」タブから追加してください。</strong></p></div><h3 id="_4-4-1-限定メニューの作成" tabindex="-1">4.4.1 限定メニューの作成 <a class="header-anchor" href="#_4-4-1-限定メニューの作成" aria-label="Permalink to &quot;4.4.1 限定メニューの作成&quot;">​</a></h3><ol><li><strong>「メニュー追加」ボタン</strong>を押す</li><li>モーダルが開く</li><li>以下を入力する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>メニュー名</td><td>✓</td><td>日本語の表示名</td></tr><tr><td>メニュー名（英語）</td><td>—</td><td>英語の表示名</td></tr><tr><td>カテゴリ</td><td>✓</td><td>ドロップダウンから選択</td></tr><tr><td>価格（税込）</td><td>✓</td><td>税込価格（円）</td></tr><tr><td>説明文</td><td>—</td><td>メニューの詳細説明</td></tr><tr><td>画像</td><td>—</td><td>メニュー写真</td></tr><tr><td>カロリー</td><td>—</td><td>kcal（数値）</td></tr><tr><td>アレルゲン</td><td>—</td><td>25 項目のチェックボックスから選択</td></tr><tr><td>オプショングループ</td><td>—</td><td>紐付けるオプション</td></tr></tbody></table><ol start="4"><li><strong>保存</strong>ボタンを押す</li><li>メニュー一覧に「<strong>限定</strong>」バッジ付きで追加される</li></ol><p>限定メニューはセルフオーダー画面で通常のメニューと同様に表示されます（「限定」バッジは管理画面のみの表示で、お客さん側には表示されません）。</p><h3 id="_4-4-2-限定メニューの一覧表示" tabindex="-1">4.4.2 限定メニューの一覧表示 <a class="header-anchor" href="#_4-4-2-限定メニューの一覧表示" aria-label="Permalink to &quot;4.4.2 限定メニューの一覧表示&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[限定メニュー] サブタブ</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 🏠 渋谷店限定 ハーブチキン [限定]    メイン  ¥1,280  [販売中]│</span></span>
<span class="line"><span>│ 🏠 季節のスペシャル丼     [限定]    メイン  ¥1,080  [品切れ]│</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p>販売中 / 品切れトグルは灰色（販売中）/ 赤色（品切れ）で切り替わります。</p><h3 id="_4-4-3-品切れ・編集・削除" tabindex="-1">4.4.3 品切れ・編集・削除 <a class="header-anchor" href="#_4-4-3-品切れ・編集・削除" aria-label="Permalink to &quot;4.4.3 品切れ・編集・削除&quot;">​</a></h3><ul><li><strong>販売中 / 品切れ</strong> ボタンで品切れ切替</li><li><strong>編集</strong> ボタンでモーダル再オープン</li><li><strong>削除</strong> ボタンで削除（確認ダイアログあり）</li></ul><hr><h2 id="_4-5-オプション・トッピング" tabindex="-1">4.5 オプション・トッピング <a class="header-anchor" href="#_4-5-オプション・トッピング" aria-label="Permalink to &quot;4.5 オプション・トッピング&quot;">​</a></h2><p>オプショングループは、メニューに付加する選択肢（トッピング、サイズ、焼き加減など）を管理する機能です。</p><p><strong>サブタブ：「オプション管理」</strong>（owner 専用）</p><h3 id="_4-5-1-オプショングループの作成" tabindex="-1">4.5.1 オプショングループの作成 <a class="header-anchor" href="#_4-5-1-オプショングループの作成" aria-label="Permalink to &quot;4.5.1 オプショングループの作成&quot;">​</a></h3><ol><li><strong>「グループ追加」ボタン</strong>を押す</li><li>モーダルが開く</li><li>以下を入力する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th><th>入力例</th></tr></thead><tbody><tr><td>グループ名</td><td>✓</td><td>日本語名</td><td>ごはんの量</td></tr><tr><td>グループ名（English）</td><td>—</td><td>英語名</td><td>Rice Size</td></tr><tr><td>選択タイプ</td><td>✓</td><td><code>single</code>（単一選択 / ラジオ）または <code>multi</code>（複数選択 / チェック）</td><td>single</td></tr><tr><td>最小選択数</td><td>—</td><td>必須選択の最小数</td><td>1</td></tr><tr><td>最大選択数</td><td>—</td><td>選択できる最大数</td><td>1</td></tr></tbody></table><ol start="4"><li><strong>保存</strong>ボタンを押す</li></ol><h3 id="_4-5-2-選択タイプの違い" tabindex="-1">4.5.2 選択タイプの違い <a class="header-anchor" href="#_4-5-2-選択タイプの違い" aria-label="Permalink to &quot;4.5.2 選択タイプの違い&quot;">​</a></h3><table tabindex="0"><thead><tr><th>タイプ</th><th>内部値</th><th>UI 表示</th><th>自動設定</th><th>例</th></tr></thead><tbody><tr><td>単一選択</td><td><code>single</code></td><td>ラジオボタン形式。1 つだけ選択</td><td>最小=1、最大=1</td><td>サイズ（S / M / L）</td></tr><tr><td>複数選択</td><td><code>multi</code></td><td>チェックボックス形式。0〜N 個選択</td><td>最小=0、最大=3</td><td>トッピング（チーズ / 卵 / ベーコン）</td></tr></tbody></table><p>選択タイプを切り替えると、min/max の値が自動で書き換わります（手動上書き可）。</p><h3 id="_4-5-3-選択肢の追加" tabindex="-1">4.5.3 選択肢の追加 <a class="header-anchor" href="#_4-5-3-選択肢の追加" aria-label="Permalink to &quot;4.5.3 選択肢の追加&quot;">​</a></h3><p>オプショングループを作成したら、そのグループに選択肢を追加します。</p><ol><li>グループのカード内にある**「+ 選択肢」ボタン**を押す</li><li>モーダルが開く</li><li>以下を入力する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th><th>入力例</th></tr></thead><tbody><tr><td>選択肢名</td><td>✓</td><td>日本語名</td><td>Lサイズ</td></tr><tr><td>選択肢名（英語）</td><td>—</td><td>英語名</td><td>Large</td></tr><tr><td>価格差（円）</td><td>—</td><td>追加料金。マイナスも可</td><td>+200 / -50</td></tr><tr><td>デフォルト</td><td>—</td><td>チェックすると初期選択される</td><td>—</td></tr></tbody></table><ol start="4"><li><strong>保存</strong>を押す</li></ol><h3 id="_4-5-4-選択肢の表示例" tabindex="-1">4.5.4 選択肢の表示例 <a class="header-anchor" href="#_4-5-4-選択肢の表示例" aria-label="Permalink to &quot;4.5.4 選択肢の表示例&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─ ごはんの量 (単一選択) (3メニュー)              [+ 選択肢] [編集] [削除] ─┐</span></span>
<span class="line"><span>│  選択: 1〜1                                                                │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  小盛り (Small)         ±0      [既定]   [編集] [削除]                     │</span></span>
<span class="line"><span>│  並盛り (Regular)       ±0                [編集] [削除]                     │</span></span>
<span class="line"><span>│  大盛り (Large)         +100円           [編集] [削除]                     │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_4-5-5-グループの有効-無効" tabindex="-1">4.5.5 グループの有効/無効 <a class="header-anchor" href="#_4-5-5-グループの有効-無効" aria-label="Permalink to &quot;4.5.5 グループの有効/無効&quot;">​</a></h3><p>グループの編集モーダルに「有効」チェックボックスがあります。無効にすると、そのグループが紐付けられたメニューでもオプション選択が表示されなくなります。</p><div class="tip custom-block"><p class="custom-block-title">使いどころ</p><p>季節限定のトッピングを一時的に無効にしたい場合や、在庫切れのオプションを停止したい場合に使います。紐付け自体を削除する必要はありません。</p></div><h3 id="_4-5-6-メニューへの紐付け" tabindex="-1">4.5.6 メニューへの紐付け <a class="header-anchor" href="#_4-5-6-メニューへの紐付け" aria-label="Permalink to &quot;4.5.6 メニューへの紐付け&quot;">​</a></h3><p>オプショングループは、テンプレートメニュー側または店舗オーバーライド側 / 限定メニュー側の編集モーダル下部から紐付けます（4.3.6 / 4.4.1 参照）。「必須」チェックを入れると注文時に必ず選択させる動作になります。</p><hr><h2 id="_4-6-今日のおすすめ" tabindex="-1">4.6 今日のおすすめ <a class="header-anchor" href="#_4-6-今日のおすすめ" aria-label="Permalink to &quot;4.6 今日のおすすめ&quot;">​</a></h2><p>「今日のおすすめ」は、日替わりで特定のメニューをセルフオーダー画面の上部に目立つように表示する機能です。</p><p><strong>サブタブ：「店舗メニュー」内のおすすめセクション</strong></p><h3 id="_4-6-1-おすすめの追加" tabindex="-1">4.6.1 おすすめの追加 <a class="header-anchor" href="#_4-6-1-おすすめの追加" aria-label="Permalink to &quot;4.6.1 おすすめの追加&quot;">​</a></h3><ol><li>「店舗メニュー」サブタブを開く</li><li>おすすめセクションのフォームが表示されている</li><li>以下を設定する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>メニュー</td><td>✓</td><td>ドロップダウンからメニューを選択（テンプレート＋限定メニュー両方表示。限定メニューは [限定] タグ付き）</td></tr><tr><td>バッジ種別</td><td>✓</td><td><code>おすすめ</code> / <code>人気</code> / <code>新着</code> / <code>限定</code> / <code>本日限り</code> の 5 種類から選択</td></tr><tr><td>コメント</td><td>—</td><td>最大 200 文字のひとこと説明（例：「本日入荷の新鮮素材で作りました」）</td></tr></tbody></table><ol start="4"><li><strong>追加</strong>ボタンを押す</li><li>おすすめ一覧にカードが追加される</li></ol><h3 id="_4-6-2-おすすめの削除" tabindex="-1">4.6.2 おすすめの削除 <a class="header-anchor" href="#_4-6-2-おすすめの削除" aria-label="Permalink to &quot;4.6.2 おすすめの削除&quot;">​</a></h3><ol><li>削除したいおすすめカードの**×ボタン**を押す</li><li>確認ダイアログで<strong>OK</strong>を押す</li><li>おすすめから削除される</li></ol><div class="info custom-block"><p class="custom-block-title">自動リセット</p><p>おすすめは日付ごとに管理されています。<strong>翌日になっても自動でリセットされません</strong>。毎日手動で更新する必要があります。前日のおすすめを削除し、新しいおすすめを追加してください。</p><p>定常運用で「前日分が残ったまま」を防ぐには、シフト開始時の業務チェックリストに「前日のおすすめ削除 → 当日分追加」を入れてください。</p></div><hr><h2 id="_4-7-品切れ管理" tabindex="-1">4.7 品切れ管理 <a class="header-anchor" href="#_4-7-品切れ管理" aria-label="Permalink to &quot;4.7 品切れ管理&quot;">​</a></h2><p>品切れの設定は以下の 3 箇所から行えます：</p><table tabindex="0"><thead><tr><th>場所</th><th>範囲</th><th>操作者</th><th>即時反映</th></tr></thead><tbody><tr><td>メニューテンプレート（カテゴリ管理タブ）</td><td><strong>全店舗</strong>で品切れ</td><td>manager 以上</td><td>✓（2 秒）</td></tr><tr><td>店舗メニューオーバーライド（店舗メニュータブ）</td><td><strong>その店舗のみ</strong>品切れ</td><td>manager 以上</td><td>✓（2 秒）</td></tr><tr><td>KDS / レジ画面（売り切れトグル）</td><td><strong>その店舗のみ</strong>品切れ</td><td>KDS / レジ操作者（device 含む）</td><td>✓（2 秒）</td></tr></tbody></table><p>品切れ設定の反映は即時です。セルフオーダー画面は 2 秒ごとにメニューバージョン（<code>menu_version</code>）をチェックしており、品切れ設定が変更されるとお客さんの画面に自動反映されます。</p><div class="tip custom-block"><p class="custom-block-title">在庫管理との連動</p><p>在庫管理機能（11 章、全契約者に標準提供）を使用している場合、食材の在庫が 0 になると、その食材を使用するメニューが自動的に品切れ表示になります（レシピ BOM 連動）。</p><p>品切れを「在庫補充して解除」する場合は在庫側もリセットしないと再び品切れに戻ります。</p></div><h3 id="_4-7-1-品切れ運用フロー-実例" tabindex="-1">4.7.1 品切れ運用フロー（実例） <a class="header-anchor" href="#_4-7-1-品切れ運用フロー-実例" aria-label="Permalink to &quot;4.7.1 品切れ運用フロー（実例）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ピークタイム</span></span>
<span class="line"><span>  ├─ 仕込み分が残り少ない → ハンディPOS で「品切れ」トグル</span></span>
<span class="line"><span>  ├─ お客さん画面 2 秒以内に「売切」表示</span></span>
<span class="line"><span>  ├─ 仕込み追加完了 → 品切れ解除トグル</span></span>
<span class="line"><span>  └─ お客さん画面 2 秒以内に再表示</span></span></code></pre></div><hr><h2 id="_4-8-カロリー・アレルゲン情報" tabindex="-1">4.8 カロリー・アレルゲン情報 <a class="header-anchor" href="#_4-8-カロリー・アレルゲン情報" aria-label="Permalink to &quot;4.8 カロリー・アレルゲン情報&quot;">​</a></h2><p>カロリーとアレルゲンの設定方法は「店舗メニューオーバーライド」または「限定メニュー」の編集モーダルで行います。詳細は 4.3.5 / 4.4.1 を参照してください。</p><p>設定した情報は、セルフオーダー画面のメニュー詳細ポップアップに表示されます。アレルゲンはアイコン付きで表示され、お客さんがアレルギーを持つ食材を含むメニューを避けるのに役立ちます。</p><hr><h2 id="_4-9-メニュー多言語対応-ai-翻訳" tabindex="-1">4.9 メニュー多言語対応（AI 翻訳） <a class="header-anchor" href="#_4-9-メニュー多言語対応-ai-翻訳" aria-label="Permalink to &quot;4.9 メニュー多言語対応（AI 翻訳）&quot;">​</a></h2><p>全契約者に標準提供されます（2026-04-09 以降、旧 pro プラン制限は撤廃）。メニューを指定した言語に一括翻訳する機能です。</p><h3 id="_4-9-1-操作手順" tabindex="-1">4.9.1 操作手順 <a class="header-anchor" href="#_4-9-1-操作手順" aria-label="Permalink to &quot;4.9.1 操作手順&quot;">​</a></h3><ol><li>「店舗メニュー」サブタブを開く</li><li><strong>「翻訳」ボタン</strong>を押す</li><li>翻訳先の言語を選択する（複数同時選択可）</li><li>全カテゴリ・全メニュー名・全説明文・全オプション名が一括で AI 翻訳されます</li><li>翻訳結果はキャッシュ（<code>menu_translations</code>）に保存され、セルフオーダー画面でお客さんの端末の言語設定に応じて自動表示されます</li></ol><h3 id="_4-9-2-対応言語-実装一覧" tabindex="-1">4.9.2 対応言語（実装一覧） <a class="header-anchor" href="#_4-9-2-対応言語-実装一覧" aria-label="Permalink to &quot;4.9.2 対応言語（実装一覧）&quot;">​</a></h3><p><code>api/store/translate-menu.php</code> の <code>$allowedLangs</code> で許可された言語のみ：</p><table tabindex="0"><thead><tr><th>言語コード</th><th>言語</th><th>備考</th></tr></thead><tbody><tr><td><code>en</code></td><td>英語</td><td>デフォルト ON（P1-31 で追加）</td></tr><tr><td><code>zh-Hans</code></td><td>中国語簡体字</td><td>デフォルト ON</td></tr><tr><td><code>ko</code></td><td>韓国語</td><td>デフォルト ON</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">zh-Hant（繁體中文）は廃止</p><p>P1-31 で運用判断により無効化（DB 既存データは残置）。台湾・香港対応を再開する場合は posla 運営に相談してください。</p></div><h3 id="_4-9-3-強制再翻訳-force-フラグ" tabindex="-1">4.9.3 強制再翻訳（force フラグ） <a class="header-anchor" href="#_4-9-3-強制再翻訳-force-フラグ" aria-label="Permalink to &quot;4.9.3 強制再翻訳（force フラグ）&quot;">​</a></h3><p>メニュー名や説明文を変更した場合は、再翻訳が必要です。</p><table tabindex="0"><thead><tr><th>ボタン</th><th>動作</th></tr></thead><tbody><tr><td>「翻訳」</td><td>未翻訳項目のみ Gemini に投げる（既存キャッシュ維持）</td></tr><tr><td>「強制再翻訳」</td><td>全項目を強制再生成（<code>force=true</code> で API 呼び出し）</td></tr></tbody></table><p>リクエスト例（フロント側内部処理）:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/store/translate-menu.php</span></span>
<span class="line"><span>{ &quot;store_id&quot;: &quot;xxx&quot;, &quot;langs&quot;: [&quot;en&quot;,&quot;zh-Hans&quot;,&quot;ko&quot;], &quot;force&quot;: false }</span></span></code></pre></div><h3 id="_4-9-4-翻訳の仕組み" tabindex="-1">4.9.4 翻訳の仕組み <a class="header-anchor" href="#_4-9-4-翻訳の仕組み" aria-label="Permalink to &quot;4.9.4 翻訳の仕組み&quot;">​</a></h3><ul><li>モデル: Gemini 2.0 Flash（POSLA サーバー側）</li><li>30 件ごとにバッチ処理</li><li>翻訳結果は <code>menu_translations</code> テーブルに保存（キャッシュ）</li><li>同一文字列の再翻訳はキャッシュを使用</li><li>API キーは POSLA 運営が一括負担（<code>posla_settings.gemini_api_key</code>）</li></ul><h3 id="_4-9-5-gemini-の癖と注意点" tabindex="-1">4.9.5 Gemini の癖と注意点 <a class="header-anchor" href="#_4-9-5-gemini-の癖と注意点" aria-label="Permalink to &quot;4.9.5 Gemini の癖と注意点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>現象</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>カタカナ語が中国語になりにくい（「ハンバーグ」が <code>汉堡</code> のままなど）</td><td>Gemini はカタカナ外来語の元語推定が弱い</td><td>強制再翻訳で改善 / 手動修正（P1-31b で改善）</td></tr><tr><td>同じ料理名が日によって違う訳になる</td><td>LLM の確率的揺らぎ</td><td>キャッシュされるので 1 度確定したら維持される</td></tr><tr><td>「特製」「自家製」が「Special」「Homemade」固定にならず文脈で変わる</td><td>Gemini の意訳挙動</td><td>強制再翻訳で安定</td></tr><tr><td>韓国語の助詞が違和感ある</td><td>機械翻訳の限界</td><td>説明文を短く区切ると改善</td></tr></tbody></table><h3 id="_4-9-6-翻訳の手動修正" tabindex="-1">4.9.6 翻訳の手動修正 <a class="header-anchor" href="#_4-9-6-翻訳の手動修正" aria-label="Permalink to &quot;4.9.6 翻訳の手動修正&quot;">​</a></h3><p>機械翻訳が不適切な場合、<code>menu_translations</code> テーブルを直接 SQL で書き換えるか、メニュー名側に英語別名（<code>name_en</code>）を入れることで対処します。<code>name_en</code> が入っていれば翻訳時にそれが優先される設計です。</p><hr><h2 id="_4-10-csv-一括インポート・エクスポート" tabindex="-1">4.10 CSV 一括インポート・エクスポート <a class="header-anchor" href="#_4-10-csv-一括インポート・エクスポート" aria-label="Permalink to &quot;4.10 CSV 一括インポート・エクスポート&quot;">​</a></h2><p>メニュー関連のデータを CSV ファイルで一括管理できます。Excel や Google Sheets で大量編集してから取り込めます。</p><h3 id="_4-10-1-エクスポート-書き出し" tabindex="-1">4.10.1 エクスポート（書き出し） <a class="header-anchor" href="#_4-10-1-エクスポート-書き出し" aria-label="Permalink to &quot;4.10.1 エクスポート（書き出し）&quot;">​</a></h3><ol><li>対象のサブタブを開く（店舗メニュー、限定メニュー等）</li><li><strong>「CSV エクスポート」ボタン</strong>を押す</li><li>CSV ファイルがダウンロードされます</li><li>ファイルは UTF-8（BOM 付き）エンコーディングで、Excel でそのまま開けます</li></ol><h3 id="_4-10-2-インポート-読み込み" tabindex="-1">4.10.2 インポート（読み込み） <a class="header-anchor" href="#_4-10-2-インポート-読み込み" aria-label="Permalink to &quot;4.10.2 インポート（読み込み）&quot;">​</a></h3><ol><li>対象のサブタブを開く</li><li><strong>「CSV インポート」ボタン</strong>を押す</li><li>CSV ファイルを選択する</li><li>インポートが実行される</li><li>結果が表示される：作成された件数、更新された件数、エラーがあればエラー内容</li></ol><div class="warning custom-block"><p class="custom-block-title">CSV インポートの注意点</p><ul><li>インポートは UPSERT 方式です（既存のデータがあれば更新、なければ新規作成）</li><li>トランザクション内で実行されるため、途中でエラーがあった場合は<strong>全件ロールバック</strong>されます</li><li>エラーがあった場合、「行 2: カテゴリが見つかりません」のように行番号とエラー内容が表示されます</li><li>大量行数（&gt;1000 行）はタイムアウトに注意。100〜500 行ずつに分割推奨</li></ul></div><h3 id="_4-10-3-csv-インポート-エクスポート対象" tabindex="-1">4.10.3 CSV インポート/エクスポート対象 <a class="header-anchor" href="#_4-10-3-csv-インポート-エクスポート対象" aria-label="Permalink to &quot;4.10.3 CSV インポート/エクスポート対象&quot;">​</a></h3><table tabindex="0"><thead><tr><th>データ</th><th>エクスポート</th><th>インポート</th><th>API</th></tr></thead><tbody><tr><td>店舗限定メニュー</td><td>✓</td><td>✓</td><td><code>/api/store/local-items-csv.php</code></td></tr><tr><td>メニューオーバーライド</td><td>✓</td><td>✓</td><td><code>/api/store/menu-overrides-csv.php</code></td></tr><tr><td>本部メニューテンプレート</td><td>✓</td><td>✓</td><td><code>/api/owner/menu-csv.php</code></td></tr><tr><td>食べ放題プラン</td><td>✓</td><td>✓</td><td>—</td></tr><tr><td>プラン専用メニュー</td><td>✓</td><td>✓</td><td>—</td></tr><tr><td>コース＋フェーズ</td><td>✓</td><td>✓</td><td>—</td></tr><tr><td>食材マスタ</td><td>✓</td><td>✓</td><td>11 章参照</td></tr><tr><td>レシピ（BOM）</td><td>✓</td><td>✓</td><td>11 章参照</td></tr></tbody></table><h3 id="_4-10-4-csv-カラム例-店舗オーバーライド" tabindex="-1">4.10.4 CSV カラム例（店舗オーバーライド） <a class="header-anchor" href="#_4-10-4-csv-カラム例-店舗オーバーライド" aria-label="Permalink to &quot;4.10.4 CSV カラム例（店舗オーバーライド）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>template_id, name, category, base_price, override_price, is_hidden, is_sold_out, override_image_url</span></span>
<span class="line"><span>abc-001, 特製唐揚げ, メイン, 880, 980, 0, 0, /uploads/karaage_shibuya.jpg</span></span>
<span class="line"><span>abc-002, ステーキ重, メイン, 1480, , 1, 0,</span></span></code></pre></div><ul><li><code>override_price</code> を空欄にすると本部 base_price 継承</li><li><code>is_hidden</code> / <code>is_sold_out</code> は 0 / 1</li><li><code>override_image_url</code> を空欄にすると本部 image_url 継承</li></ul><hr><h2 id="_4-11-スマレジ連携-メニューインポート" tabindex="-1">4.11 スマレジ連携（メニューインポート） <a class="header-anchor" href="#_4-11-スマレジ連携-メニューインポート" aria-label="Permalink to &quot;4.11 スマレジ連携（メニューインポート）&quot;">​</a></h2><p>owner 専用機能。スマレジ（Smaregi）に登録済みの商品マスタを POSLA のメニューテンプレートに一括取り込みします。詳細は <strong>22 章: スマレジ連携</strong> を参照。</p><h3 id="_4-11-1-主な特徴" tabindex="-1">4.11.1 主な特徴 <a class="header-anchor" href="#_4-11-1-主な特徴" aria-label="Permalink to &quot;4.11.1 主な特徴&quot;">​</a></h3><ul><li><strong>非破壊インポート</strong>（P1-20）: 既存メニューは維持。スマレジにある新商品だけ追加</li><li>カテゴリも同時に同期</li><li><code>api/smaregi/import-menu.php</code> 経由で OAuth 認証付き</li><li>インポート後に自動で多言語翻訳（<code>translate_menu_core()</code> 呼び出し）</li></ul><h3 id="_4-11-2-操作手順-要約" tabindex="-1">4.11.2 操作手順（要約） <a class="header-anchor" href="#_4-11-2-操作手順-要約" aria-label="Permalink to &quot;4.11.2 操作手順（要約）&quot;">​</a></h3><ol><li>owner-dashboard &gt;「スマレジ連携」タブ</li><li>OAuth 認証（初回のみ） 3.「商品マスタを取り込む」ボタンを押す</li><li>プログレス表示（差分のみ取り込み）</li><li>完了後、自動で多言語翻訳が走る</li></ol><p>詳細手順は 22 章のフル粒度ガイドを参照してください。</p><hr><h2 id="_4-x-よくある質問-faq-30-件" tabindex="-1">4.X よくある質問（FAQ 30 件） <a class="header-anchor" href="#_4-x-よくある質問-faq-30-件" aria-label="Permalink to &quot;4.X よくある質問（FAQ 30 件）&quot;">​</a></h2><h3 id="a-3-層構造・本部マスタ" tabindex="-1">A. 3 層構造・本部マスタ <a class="header-anchor" href="#a-3-層構造・本部マスタ" aria-label="Permalink to &quot;A. 3 層構造・本部マスタ&quot;">​</a></h3><p><strong>Q1. 本部マスタと店舗メニューの違いは?</strong> A. マスタ（<code>menu_templates</code>） = 全店共通の基礎情報。店舗（<code>store_menu_overrides</code>） = 店舗ごとの価格・表示カスタム。アドオン契約時のみ本部マスタ編集が owner 専用。</p><p><strong>Q2. アドオン契約と未契約では何が違う?</strong> A. 契約時は本部マスタが owner-dashboard 専用、店舗側は readonly。未契約時は店舗 dashboard から本部マスタを直接編集できる（事実上）。</p><p><strong>Q3. 店舗独自メニューを本部に追加されたくない</strong> A. 「限定メニュー」タブから追加。本部マスタには入りません。「店舗メニュー」タブから新規追加すると本部マスタに入る点に注意。</p><p><strong>Q4. 価格を店舗ごとに変えたい</strong> A. 「店舗メニュー」の編集モーダルで <code>価格</code> 欄に値を入れて保存。本部マスタは維持されます。空欄に戻すと本部価格に戻る。</p><p><strong>Q5. 本部マスタの価格を変えたら全店舗に反映される?</strong> A. はい。ただし店舗オーバーライドで <code>price</code> を上書きしている店舗は、その店舗の上書き値が優先されます。</p><h3 id="b-カテゴリ・並び順" tabindex="-1">B. カテゴリ・並び順 <a class="header-anchor" href="#b-カテゴリ・並び順" aria-label="Permalink to &quot;B. カテゴリ・並び順&quot;">​</a></h3><p><strong>Q6. カテゴリの並び順は?</strong> A. カテゴリ管理で表示順を数値指定。小さいほど上。10 飛ばし運用を推奨。</p><p><strong>Q7. カテゴリを削除したらメニューはどうなる?</strong> A. 「カテゴリなし」状態になります。事前にメニューを別カテゴリに移動推奨。</p><p><strong>Q8. カテゴリ名を多言語化したい</strong> A. 「カテゴリ名（英語）」欄に英語名を入れる + 4.9 の一括翻訳で zh-Hans / ko も生成。</p><h3 id="c-品切れ・在庫連動" tabindex="-1">C. 品切れ・在庫連動 <a class="header-anchor" href="#c-品切れ・在庫連動" aria-label="Permalink to &quot;C. 品切れ・在庫連動&quot;">​</a></h3><p><strong>Q9. 品切れはどこから設定?</strong> A. 3 箇所（テンプレ / オーバーライド / KDS）。範囲が異なる（4.7 表参照）。</p><p><strong>Q10. 品切れ解除しても客側で買えない</strong> A. 在庫管理機能で食材在庫が 0 のままだと自動で品切れに戻る。在庫側もリセット。</p><p><strong>Q11. 本部側で品切れにすると店舗で解除できない?</strong> A. はい。本部品切れ（テンプレ側 <code>is_sold_out=1</code>）は全店共通で、店舗側で解除不可。</p><p><strong>Q12. 売切表示はどれくらいで反映する?</strong> A. 約 2 秒。お客さん画面が 2 秒ごとに <code>menu_version</code> をポーリング。</p><h3 id="d-オプション・トッピング" tabindex="-1">D. オプション・トッピング <a class="header-anchor" href="#d-オプション・トッピング" aria-label="Permalink to &quot;D. オプション・トッピング&quot;">​</a></h3><p><strong>Q13. オプショングループの使い所</strong> A. トッピング / 辛さ / 麺の硬さ / ごはんの量 など、同一品目の選択肢。</p><p><strong>Q14. 必須オプションって何?</strong> A. 注文時に必ず選ばないとカートに入らないオプション。「ごはんの量」など。</p><p><strong>Q15. オプションの一時無効化は?</strong> A. グループ編集で「有効」チェックを外す。紐付けを削除する必要なし。</p><p><strong>Q16. オプションに価格差マイナスを入れられる?</strong> A. 可能。例: 「ごはん少なめ -50 円」。</p><h3 id="e-多言語翻訳" tabindex="-1">E. 多言語翻訳 <a class="header-anchor" href="#e-多言語翻訳" aria-label="Permalink to &quot;E. 多言語翻訳&quot;">​</a></h3><p><strong>Q17. 多言語翻訳は無料?</strong> A. POSLA 運営が Gemini API 費を負担。テナントは無料。</p><p><strong>Q18. 一括翻訳と強制再翻訳の違い</strong> A. 一括 = 未翻訳項目のみ。強制再翻訳 = キャッシュ無視で全件再生成。</p><p><strong>Q19. カテゴリ名の中国語化が変</strong> A. カタカナ外来語は翻訳されにくい（P1-31b で改善）。手動修正 or <code>name_en</code> を充実させる。</p><p><strong>Q20. 繁體中文（zh-Hant）が選べない</strong> A. P1-31 で廃止。再開希望なら posla 運営に相談。</p><p><strong>Q21. 翻訳が反映されない</strong> A. ブラウザキャッシュ。Ctrl+F5 で強制リロード。</p><h3 id="f-csv-スマレジ" tabindex="-1">F. CSV / スマレジ <a class="header-anchor" href="#f-csv-スマレジ" aria-label="Permalink to &quot;F. CSV / スマレジ&quot;">​</a></h3><p><strong>Q22. CSV インポートの形式</strong> A. テンプレートダウンロード可。カラム: template_id / name / category / base_price / override_price / is_hidden / is_sold_out / image_url 等。</p><p><strong>Q23. CSV 文字化け</strong> A. UTF-8 BOM 付きで保存。Excel は「名前を付けて保存」→「CSV UTF-8」を選択。</p><p><strong>Q24. スマレジインポートで既存メニューが消える?</strong> A. 消えません（非破壊インポート、P1-20）。既存は維持し、新商品のみ追加。</p><p><strong>Q25. スマレジ連携エラー (OAuth 切れ)</strong> A. owner-dashboard「スマレジ連携」タブから再認証。</p><h3 id="g-画像・運用" tabindex="-1">G. 画像・運用 <a class="header-anchor" href="#g-画像・運用" aria-label="Permalink to &quot;G. 画像・運用&quot;">​</a></h3><p><strong>Q26. 画像が表示されない</strong> A. 画像 URL が HTTPS か確認。HTTP だとブラウザでブロックされる（混在コンテンツ）。</p><p><strong>Q27. 画像のサイズは?</strong> A. アップロード時に 800×800 以下に自動リサイズ（品質 0.8 JPEG）。元画像 5MB まで。</p><p><strong>Q28. メニュー編集権限を staff に渡したい</strong> A. 不可。<code>manager</code> 以上のみ（セキュリティ上）。staff の業務範囲外。</p><p><strong>Q29. 削除したメニューを復元したい</strong> A. 不可。事前バックアップ（CSV エクスポート）推奨。過去注文データは <code>orders.items</code> JSON に名称・価格スナップショットが残っているのでレポートには影響なし。</p><p><strong>Q30. メニュー数の上限は?</strong> A. ソフト上限なし。実用上 1000 件超えるとセルフオーダー画面の描画が遅くなるためカテゴリ整理推奨。</p><hr><h2 id="_4-y-トラブルシューティング" tabindex="-1">4.Y トラブルシューティング <a class="header-anchor" href="#_4-y-トラブルシューティング" aria-label="Permalink to &quot;4.Y トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>メニューが表示されない</td><td>カテゴリ未設定 / <code>is_active=0</code></td><td>カテゴリ設定 + メニュー有効化</td></tr><tr><td>価格変更が反映されない</td><td>キャッシュ（最大 3 分） / <code>menu_version</code> 未更新</td><td>3 分待つ or リロード or 該当メニューを再保存</td></tr><tr><td>翻訳ボタンを押しても反応なし</td><td>Gemini API キー未設定</td><td>POSLA 運営に連絡（<code>posla_settings.gemini_api_key</code>）</td></tr><tr><td>翻訳結果が前と同じ</td><td>キャッシュヒット</td><td>「強制再翻訳」を使う</td></tr><tr><td>CSV 文字化け</td><td>UTF-8 でない / BOM なし</td><td>UTF-8 BOM 付きで保存</td></tr><tr><td>CSV インポートで全件ロールバック</td><td>どこかの行でエラー</td><td>エラー行番号を見て修正 → 再投入</td></tr><tr><td>スマレジ連携で「未認証」</td><td>OAuth トークン切れ</td><td>再認証</td></tr><tr><td>画像アップロードで失敗</td><td>ファイル 5MB 超 / 拡張子非対応</td><td>縮小 / JPG・PNG・WebP・GIF のみ</td></tr><tr><td>画像が表示されない</td><td>HTTP 配信 / 404</td><td>HTTPS 配信を確認</td></tr><tr><td>限定メニューが本部にも出る</td><td>「店舗メニュー」タブから追加してしまった</td><td>削除して「限定メニュー」タブから再追加</td></tr><tr><td>アドオン契約後に編集ロックされた</td><td>hq_menu_broadcast=1 で readonly</td><td>owner-dashboard「本部メニュー」から編集</td></tr><tr><td>品切れ解除しても客側に出ない</td><td>在庫連動で再度品切れ</td><td>在庫もリセット</td></tr><tr><td>カテゴリの並び順が変</td><td>表示順の数値が同じ</td><td>一意な数値を入れる</td></tr><tr><td>オプション「必須」なのに選択スキップされる</td><td>min_select=0 の設定漏れ</td><td>min_select≥1 に修正</td></tr><tr><td>お客さん画面で旧メニュー名</td><td>menu_translations キャッシュ古い</td><td>強制再翻訳</td></tr></tbody></table><hr><h2 id="_4-z-データベース構造-運営向け" tabindex="-1">4.Z データベース構造（運営向け） <a class="header-anchor" href="#_4-z-データベース構造-運営向け" aria-label="Permalink to &quot;4.Z データベース構造（運営向け）&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">通常テナントは読まなくて OK</p><h3 id="主要テーブル" tabindex="-1">主要テーブル <a class="header-anchor" href="#主要テーブル" aria-label="Permalink to &quot;主要テーブル&quot;">​</a></h3><table tabindex="0"><thead><tr><th>テーブル</th><th>役割</th><th>主キー</th><th>主な FK</th></tr></thead><tbody><tr><td><code>menu_templates</code></td><td>本部マスタ</td><td><code>id</code> (UUID)</td><td><code>tenant_id</code>, <code>category_id</code></td></tr><tr><td><code>store_menu_overrides</code></td><td>店舗オーバーライド</td><td><code>id</code></td><td><code>store_id</code>, <code>template_id</code></td></tr><tr><td><code>store_local_items</code></td><td>店舗限定品</td><td><code>id</code></td><td><code>store_id</code>, <code>category_id</code></td></tr><tr><td><code>categories</code></td><td>カテゴリ</td><td><code>id</code></td><td><code>tenant_id</code></td></tr><tr><td><code>option_groups</code></td><td>オプショングループ</td><td><code>id</code></td><td><code>tenant_id</code></td></tr><tr><td><code>option_items</code> / <code>option_choices</code></td><td>選択肢</td><td><code>id</code></td><td><code>group_id</code></td></tr><tr><td><code>menu_option_groups</code></td><td>メニュー × オプション紐付け</td><td>(template_id, group_id)</td><td>—</td></tr><tr><td><code>menu_translations</code></td><td>翻訳キャッシュ</td><td>(item_type, item_id, lang)</td><td>—</td></tr><tr><td><code>time_limit_plans</code></td><td>食べ放題プラン</td><td><code>id</code></td><td><code>store_id</code></td></tr><tr><td><code>course_templates</code> / <code>course_phases</code></td><td>コース料理</td><td><code>id</code></td><td><code>store_id</code></td></tr><tr><td><code>ingredients</code> / <code>menu_ingredients</code></td><td>食材・レシピ（C-5 / 11 章）</td><td><code>id</code></td><td><code>store_id</code>, <code>template_id</code></td></tr></tbody></table><h3 id="主要-api" tabindex="-1">主要 API <a class="header-anchor" href="#主要-api" aria-label="Permalink to &quot;主要 API&quot;">​</a></h3><ul><li><code>GET/POST/PATCH/DELETE /api/owner/menu-templates.php</code> — 本部メニュー（owner 専用）</li><li><code>GET/POST /api/owner/menu-csv.php</code> — 本部メニュー CSV</li><li><code>GET/POST/PATCH/DELETE /api/owner/categories.php</code> — カテゴリ管理</li><li><code>GET/POST/PATCH/DELETE /api/owner/option-groups.php</code> — オプショングループ</li><li><code>GET/PATCH /api/store/menu-overrides.php</code> — 店舗オーバーライド</li><li><code>GET/POST /api/store/menu-overrides-csv.php</code> — オーバーライド CSV</li><li><code>GET/POST/PATCH/DELETE /api/store/local-items.php</code> — 店舗限定メニュー</li><li><code>GET/POST /api/store/local-items-csv.php</code> — 限定メニュー CSV</li><li><code>POST /api/store/translate-menu.php</code> — Gemini 経由の多言語翻訳</li><li><code>POST /api/smaregi/import-menu.php</code> — スマレジから一括インポート（owner 専用）</li></ul><h3 id="フロント-js" tabindex="-1">フロント JS <a class="header-anchor" href="#フロント-js" aria-label="Permalink to &quot;フロント JS&quot;">​</a></h3><ul><li><code>public/admin/js/category-editor.js</code> — カテゴリ管理</li><li><code>public/admin/js/menu-template-editor.js</code> — 本部マスタ管理</li><li><code>public/admin/js/menu-override-editor.js</code> — 店舗オーバーライド（<code>_isHqLocked</code> 制御）</li><li><code>public/admin/js/local-item-editor.js</code> — 限定メニュー</li><li><code>public/admin/js/option-group-editor.js</code> — オプショングループ + 選択肢</li><li><code>public/admin/js/time-limit-plan-editor.js</code> — 食べ放題プラン</li><li><code>public/admin/js/course-editor.js</code> — コース料理</li></ul><h3 id="メニューリゾルバ" tabindex="-1">メニューリゾルバ <a class="header-anchor" href="#メニューリゾルバ" aria-label="Permalink to &quot;メニューリゾルバ&quot;">​</a></h3><p><code>api/lib/menu-resolver.php</code> の <code>resolve_store_menu($pdo, $storeId)</code> が 3 層を統合してセルフオーダー / KDS に返します：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. menu_templates から tenant_id 配下の全件取得</span></span>
<span class="line"><span>2. store_menu_overrides で is_hidden=1 のものを除外、price/image を上書き</span></span>
<span class="line"><span>3. store_local_items を merge</span></span>
<span class="line"><span>4. オプショングループ（menu_option_groups）を join</span></span>
<span class="line"><span>5. menu_translations から該当言語の訳を join</span></span>
<span class="line"><span>→ お客さん画面に渡す</span></span></code></pre></div></div><hr><h2 id="関連章" tabindex="-1">関連章 <a class="header-anchor" href="#関連章" aria-label="Permalink to &quot;関連章&quot;">​</a></h2><ul><li><a href="./11-inventory.html">11. 在庫・レシピ</a> — 食材 BOM と品切れ自動連動</li><li><a href="./14-ai.html">14. AI アシスタント</a> — Gemini API 共通設定</li><li><a href="./15-owner.html">15. オーナーダッシュボード</a> — 本部マスタ編集画面</li><li><a href="./22-smaregi-full.html">22. スマレジ連携</a> — メニュー一括取り込み</li></ul><hr><h2 id="更新履歴" tabindex="-1">更新履歴 <a class="header-anchor" href="#更新履歴" aria-label="Permalink to &quot;更新履歴&quot;">​</a></h2><ul><li><strong>以前</strong>: 基本機能（383 行）</li><li><strong>2026-04-18</strong>: フル粒度化、3 層構造 + アドオン + FAQ + トラブル + 技術補足 追加（542 行）</li><li><strong>2026-04-19</strong>: Phase B Batch-6 でフル粒度書き直し。チェックリスト / ASCII 描写 / 実例ブロック / FAQ 30 件 / トラブルシューティング拡張 / アレルゲン 25 項目 / 翻訳仕様 / CSV 詳細 / API・JS 一覧</li></ul>`,248)])])}const b=a(o,[["render",l]]);export{u as __pageData,b as default};
